        vector<int> prime_table::factorize(int val) const {
            if(val==1)return{1};
            int div = (*this)[val], count = 0;
            while(val%div==0){
                val/=div;
                count++;
            }
            vector<int> res = this->factorize(val);
            for(int i=1,ori_sz=(int)res.size(),mult=1;i<=count;++i){
                mult*=div;
                for(int j=0;j<ori_sz;++j){
                    res.push_back(res[j]*mult);
                }
            }
            return res;
        }
