    }
    void add(int x,int v){
        auto now=root;
        auto dfs=[&](auto&dfs,Node*now,int high,int sl,int sr)->void{
            if(high==0){
                now->size+=v;
                return;
            }
            int tar=x>>(high-1)&1;
            if(now->ch[tar]==0)now->ch[tar]=new Node();
            if(tar)dfs(dfs,now->ch[tar],high-1,sl+sr>>1,sr);
            else dfs(dfs,now->ch[tar],high-1,sl,sl+sr>>1);
            now->size+=v;
        };
        dfs(dfs,root,depth,0,1<<depth);
    }

    //[0,r)
    int get_count(int r){
        int ans=0;
        auto dfs=[&](auto&dfs,Node*now,int sl,int sr)->void{
            if(sr<=r){
                ans+=now->size;
                return;
            }
            if(sl>=r)return;
            if(now->ch[0]==0)now->ch[0]=new Node();
            if(now->ch[1]==0)now->ch[1]=new Node();
            dfs(dfs,now->ch[0],sl,((ll)sl+sr)>>1);
